  if(m){let d=m[1],mo=m[2],y=m[3];if(y.length===2)y='20'+y;return `${y}-${mo.padStart(2,'0')}-${d.padStart(2,'0')}`;}
  return s; }
let ultimaFechaYopago = null;
const _fechasPresentes = new Set();   // todas las fechas ya en el Yopago (idempotencia en Append)
for (let _r = 2; _r <= ultimaFilaConDatos; _r++) {
  let _vf = ws.getRow(_r).getCell(1).value;
  if (_vf == null) continue;
  if (typeof _vf === 'object' && 'result' in _vf) _vf = _vf.result;
  const _isDate = (_vf instanceof Date)
    || Object.prototype.toString.call(_vf) === '[object Date]'
    || (_vf && typeof _vf.getMonth === 'function');
  const _f = _isDate ? new Date(_vf).toISOString().slice(0,10) : _normF(_vf);
  if (_f && /^\d{4}-\d{2}-\d{2}$/.test(_f)) {
    _fechasPresentes.add(_f);   // idempotencia: registrar TODAS las fechas ya presentes
    if (ultimaFechaYopago === null || _f > ultimaFechaYopago) ultimaFechaYopago = _f;
  }
}
// === FIN FIX 1B+ ===

return [{
  json: {
    sheetName: sheetName,
    headers,
    ultimaFilaConDatos,
    ultimaFechaYopago,
    fechasPresentes: Array.from(_fechasPresentes),
    headerCount: headers.length,
    _hojaNueva,
    _plantillaSheet,
  },
  binary: item.binary
}];

// Append recargas a Yopago v5 (CONTROL DE FECHAS + IDEMPOTENCIA por fecha) — 2026-06-17
// MANUAL: solo las fechas elegidas. AUTO: posteriores a la ultima del Yopago.
// IDEMPOTENCIA (NUEVO): NUNCA re-agrega una fecha que YA esta en el Yopago -> re-disparar no duplica.

const yopagoData = $('Read Yopago mes actual').first().json;
const recargasNuevas = $('Aggregate todas las filas').first().json.data || [];
const ultimaFechaYopago = yopagoData.ultimaFechaYopago || null;
const fechasPresentes = new Set(yopagoData.fechasPresentes || []);  // fechas ya en el Yopago

// normFecha robusta: tolera Date, serial de Excel (re-guardado del .xlsx), ISO con T/Z, dd-mm-yyyy, dd/mm/yy.
function normFecha(s) {
  if (s == null) return '';
  if (s instanceof Date || Object.prototype.toString.call(s) === '[object Date]') {
    const d = new Date(s); if (!isNaN(d)) return d.toISOString().slice(0, 10);
  }
  // Serial de Excel SOLO en columna fecha (numero puro 43800-49300 ~ 2019..2034)
  if (typeof s === 'number' || /^\d{4,5}(\.\d+)?$/.test(String(s).trim())) {
    const n = parseFloat(s);
    if (n >= 43800 && n <= 49300) { const d = new Date(Math.round((n - 25569) * 86400 * 1000)); if (!isNaN(d)) return d.toISOString().slice(0, 10); }
  }
  s = String(s).trim(); if (!s) return ''; s = s.split(' ')[0].split('T')[0];
  let m = s.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})/);
