for (const r of recargasNuevas) {
  const _raw = String(r['Fecha'] || r.fecha || '').trim();
  if (_raw && !_esFechaOK(normFecha(r['Fecha'] != null ? r['Fecha'] : r.fecha))) {
    fechasIlegibles++; if (_ilegiblesEj.size < 5) _ilegiblesEj.add(_raw.slice(0, 25));
  }
}

function tomar(r, fNorm) {
  // IDEMPOTENCIA: si la fecha ya esta en el Yopago, NO re-agregar (evita duplicado en re-disparo)
  if (fechasPresentes.has(fNorm)) { fechasYaPresentesSet.add(fNorm); return false; }
  recargasFiltradas.push(r); fechasNuevasSet.add(fNorm); return true;
}

if (fechasSel) {
  modoFiltro = 'manual';
  const selSet = new Set(fechasSel);
  for (const r of recargasNuevas) {
    const fNorm = normFecha(r['Fecha'] || r.fecha || '');
    if (fNorm && selSet.has(fNorm)) { if (!tomar(r, fNorm)) saltadas++; }
    else { saltadas++; if (fNorm) fechasSaltadasSet.add(fNorm); }
  }
} else if (corteFecha) {
  modoFiltro = 'auto';
  for (const r of recargasNuevas) {
    const fNorm = normFecha(r['Fecha'] || r.fecha || '');
    if (fNorm && fNorm > corteFecha) { if (!tomar(r, fNorm)) saltadas++; }
    else { saltadas++; if (fNorm) fechasSaltadasSet.add(fNorm); }
  }
} else {
  modoFiltro = 'sin_corte';
  for (const r of recargasNuevas) {
    const fNorm = normFecha(r['Fecha'] || r.fecha || '');
    if (fNorm) { if (!tomar(r, fNorm)) saltadas++; } else { recargasFiltradas.push(r); }
  }
}

// ORDEN CRONOLOGICO ascendente
recargasFiltradas.sort((a, b) => {
  const fa = normFecha(a['Fecha'] || a.fecha || ''); const fb = normFecha(b['Fecha'] || b.fecha || '');
  return fa < fb ? -1 : (fa > fb ? 1 : 0);
});

if (recargasFiltradas.length === 0) {
  // Si TODO lo elegido ya estaba en el Yopago -> idempotencia (no es error de datos)
  if (fechasYaPresentesSet.size > 0) {
    throw new Error(`[FECHAS_YA_PROCESADAS] Las fechas [${Array.from(fechasYaPresentesSet).sort().join(', ')}] YA estan en el Yopago. No se re-agregan (idempotencia: re-disparar no duplica). NO se modifico el Yopago. Si necesitas re-procesar, primero corrige/limpia esas fechas manualmente.`);
  }
  const detalle = fechasSel
    ? `Ninguna recarga coincide con las fechas elegidas [${fechasSel.join(', ')}]. Fechas presentes en cajas: ${Array.from(fechasSaltadasSet).sort().join(', ')||'ninguna'}.`
    : (corteFecha
        ? `Todas las ${recargasNuevas.length} recargas tienen fecha <= ${corteFecha} (ultima en Yopago). Fechas en cajas: ${Array.from(fechasSaltadasSet).sort().join(', ')||'ninguna'}.`
        : `No hay recargas para agregar.`);
  throw new Error(`[SIN_RECARGAS_NUEVAS] No hay recargas para procesar. ${detalle} Probable: re-disparo del mismo dia o cajas ya procesadas. NO se modifico el Yopago.`);
}

return [{
  json: {
    recargas_nuevas: recargasFiltradas,
    sheetName: yopagoData.sheetName,
    headers: yopagoData.headers,
    ultimaFilaConDatos: yopagoData.ultimaFilaConDatos,
    total: recargasFiltradas.length,
    _filtro_fechas: {
      modo: modoFiltro,
      fechas_elegidas: fechasSel || null,
      ultima_fecha_yopago: corteFecha,
      recargas_originales: recargasNuevas.length,
      recargas_agregadas: recargasFiltradas.length,
      recargas_saltadas: saltadas,
      fechas_agregadas: Array.from(fechasNuevasSet).sort(),
      fechas_saltadas: Array.from(fechasSaltadasSet).sort(),
      fechas_ya_presentes_omitidas: Array.from(fechasYaPresentesSet).sort(),  // idempotencia
      fechas_ilegibles: fechasIlegibles,  // ALERTA: recargas con fecha que no se pudo leer
      ejemplos_fechas_ilegibles: Array.from(_ilegiblesEj),
    },
  },
  binary: $('Read Yopago mes actual').first().binary
}];

// === VALIDACION_ROBUSTA_XLSX v2 ===
function _validarXLSX(buf, nombreArchivo) {
  const nombre = nombreArchivo || 'archivo';
  if (!buf || buf.length === 0) throw new Error(`[XLSX_VACIO] El archivo "${nombre}" llego vacio (0 bytes). Re-subir al Drive correctamente.`);
  if (buf.length < 500) throw new Error(`[XLSX_PEQUENO] El archivo "${nombre}" es demasiado pequeno (${buf.length} bytes). Re-subir al Drive.`);
